request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?org2Id ?org2Name ?modelCount2 WHERE {
  # model count of the reference organization
  {
    SELECT (COUNT(DISTINCT ?model1) AS ?modelCount1) WHERE {
      ?org1 a bboExt:Organization .
      ?org1 tai:organizationId "985f88f59e8b4962a0a2c2fec001b6d1" .
      ?model1 tai:belongsTo ?org1 .
    }
  }

  # all organizations with same count
  {
    SELECT ?org2Id ?org2Name (COUNT(DISTINCT ?model2) AS ?modelCount2) WHERE {
      ?org2 a bboExt:Organization .
      ?org2 tai:organizationId ?org2Id .
      OPTIONAL { ?org2 rdfs:label ?org2Name . }
      ?model2 tai:belongsTo ?org2 .
    }
    GROUP BY ?org2Id ?org2Name
  }

  FILTER(?modelCount2 = ?modelCount1)
}
ORDER BY ?org2Id
